import play.api._
import play.api.mvc._
import scala.io.Source

class FileController extends Controller {
  def download(filename: String) = Action.async { request =>
    val filePath = s"uploads/$filename" // construct the full path to your uploaded files, you may need a subdirectory for organized storage if needed in future updates or new versions of this application could use different directories structure as well 
    
    Source.fromFile(filePath).getLines().map(line => Ok(line)).as("text/plain") // return the file content with correct MIME type, you may need to adapt it depending on your needs and how files are stored in this case (e.g., binary or text)
  }  
}